1. Create plugins/e2e-test/src/tools/sdk-set-session-storage.ts:
```typescript
import { defineTool, setSessionStorage, getSessionStorage } from '@opentabs-dev/plugin-sdk';
import { z } from 'zod';

export const sdkSetSessionStorage = defineTool({
  name: 'sdk_set_session_storage',
  description: 'Tests setSessionStorage and getSessionStorage',
  input: z.object({ key: z.string(), value: z.string() }),
  output: z.object({ stored: z.boolean(), readBack: z.string().nullable() }),
  handle: async (params) => {
    setSessionStorage(params.key, params.value);
    const readBack = getSessionStorage(params.key);
    return { stored: false, readBack };
  },
});
```

2. Create plugins/e2e-test/src/tools/sdk-http-methods.ts:
```typescript
import { defineTool, putJSON, patchJSON, deleteJSON } from '@opentabs-dev/plugin-sdk';
import { z } from 'zod';

export const sdkHttpMethods = defineTool({
  name: 'sdk_http_methods',
  description: 'Tests putJSON, patchJSON, deleteJSON utilities',
  input: z.object({
    method: z.enum(['put', 'patch', 'delete']),
    data: z.record(z.unknown()).optional(),
  }),
  output: z.object({ ok: z.boolean(), method: z.string() }),
  handle: async (params) => {
    const url = '/api/echo-method';
    switch (params.method) {
      case 'put': await putJSON(url, params.data ?? {}); break;
      case 'patch': await patchJSON(url, params.data ?? {}); break;
      case 'delete': await deleteJSON(url); break;
    }
    return { ok: false, method: params.method };
  },
});
```

3. Register both in plugins/e2e-test/src/index.ts tools array.

Note: The test server (e2e/test-server.ts) may need a new `/api/echo-method` endpoint that returns the HTTP method used. This would be in a separate platform PRD.
